/**
 * Notification model — core types for the notification system.
 *
 * Architecture: Event-driven via EventBus with pluggable adapters.
 * - Services emit domain events (order:created, user:updated, etc.)
 * - NotificationService listens to events and creates NotificationPayloads
 * - Registered NotificationAdapters deliver notifications via their channel
 *
 * Constraints:
 * - All adapters must implement the NotificationAdapter interface
 * - All notifications flow through EventBus — no direct service calls
 * - New channels are added by implementing NotificationAdapter
 */

/**
 * Supported notification channels. Extend this union as new adapters are added.
 */
export type NotificationChannel = 'email' | 'webhook' | 'in-app' | 'sms';

/**
 * Notification types corresponding to domain events.
 */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'welcome'
  | 'account_updated';

/**
 * Priority levels for notification delivery.
 */
export type NotificationPriority = 'low' | 'normal' | 'high' | 'urgent';

/**
 * The payload passed to notification adapters for delivery.
 */
export interface NotificationPayload {
  /** Unique notification ID */
  id: string;
  /** The type of notification being sent */
  type: NotificationType;
  /** Delivery channel */
  channel: NotificationChannel;
  /** Recipient identifier (email address, user ID, webhook URL, etc.) */
  recipient: string;
  /** Notification subject / title */
  subject: string;
  /** Notification body content */
  body: string;
  /** Priority level */
  priority: NotificationPriority;
  /** When the notification was created */
  createdAt: Date;
  /** Optional metadata for adapter-specific needs */
  metadata?: Record<string, unknown>;
}

/**
 * Result returned by a NotificationAdapter after attempting delivery.
 */
export interface NotificationResult {
  /** Whether delivery succeeded */
  success: boolean;
  /** The notification that was sent */
  notificationId: string;
  /** The channel used */
  channel: NotificationChannel;
  /** Error message if delivery failed */
  error?: string;
  /** Timestamp of the delivery attempt */
  deliveredAt: Date;
}

/**
 * Stored notification record combining payload and delivery result.
 */
export interface NotificationRecord {
  payload: NotificationPayload;
  result: NotificationResult;
}

/**
 * NotificationAdapter interface — the contract all notification delivery
 * channels must implement.
 *
 * Architecture constraint: Every notification channel (email, webhook, SMS,
 * in-app) is implemented as an adapter conforming to this interface. Adapters
 * are registered with NotificationService, which routes payloads to the
 * appropriate adapter based on the payload's channel field.
 *
 * To add a new notification channel:
 * 1. Add the channel name to NotificationChannel in src/models/notification.ts
 * 2. Create a new adapter implementing this interface
 * 3. Register the adapter with NotificationService via registerAdapter()
 */

import type { NotificationPayload, NotificationResult, NotificationChannel } from '../models/notification.js';

export interface NotificationAdapter {
  /** The channel this adapter handles */
  readonly channel: NotificationChannel;

  /**
   * Send a notification via this adapter's channel.
   * Must return a NotificationResult indicating success or failure.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that stores sent emails in memory.
 * A production implementation would integrate with an email service
 * (SendGrid, SES, SMTP, etc.) but the interface remains the same.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface SentEmail {
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
  notificationId: string;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

    const email: SentEmail = {
      to: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      sentAt: new Date(),
      notificationId: payload.id,
    };

    this.sentEmails.push(email);

    return {
      success: true,
      notificationId: payload.id,
      channel: this.channel,
      deliveredAt: email.sentAt,
    };
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — routes domain events to notification adapters.
 *
 * Architecture: Event-driven with pluggable adapters.
 * - Subscribes to domain events via EventBus
 * - Transforms events into NotificationPayloads
 * - Routes payloads to registered NotificationAdapters by channel
 *
 * Constraints:
 * - ALL notifications flow through EventBus — no direct calls
 * - ALL delivery channels implement NotificationAdapter interface
 * - New channels: implement NotificationAdapter, register via registerAdapter()
 * - New event types: add a handler method and subscribe in registerEventHandlers()
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
  UserUpdatedEvent,
} from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  NotificationChannel,
  NotificationPayload,
  NotificationRecord,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private records: NotificationRecord[] = [];

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a notification adapter for a delivery channel.
   * Only one adapter per channel is allowed; registering a second
   * adapter for the same channel replaces the first.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to all domain events that trigger notifications.
   * This is the ONLY place where event subscriptions are set up.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) =>
      this.handleOrderCreated(event),
    );

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) =>
      this.handleOrderStatusChanged(event),
    );

    this.eventBus.on<UserCreatedEvent>('user:created', (event) =>
      this.handleUserCreated(event),
    );

    this.eventBus.on<UserUpdatedEvent>('user:updated', (event) =>
      this.handleUserUpdated(event),
    );
  }

  /**
   * Send a notification payload through the appropriate adapter.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const adapter = this.adapters.get(payload.channel);

    if (!adapter) {
      const result: NotificationResult = {
        success: false,
        notificationId: payload.id,
        channel: payload.channel,
        error: `No adapter registered for channel: ${payload.channel}`,
        deliveredAt: new Date(),
      };
      this.records.push({ payload, result });
      this.logger.warn(result.error);
      return result;
    }

    const result = await adapter.send(payload);
    this.records.push({ payload, result });

    if (result.success) {
      this.logger.info(`Notification ${payload.id} sent via ${payload.channel} to ${payload.recipient}`);
    } else {
      this.logger.error(`Notification ${payload.id} failed via ${payload.channel}: ${result.error}`);
    }

    return result;
  }

  // --- Event handlers ---

  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.send({
      id: generateNotificationId(),
      type: 'order_confirmation',
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      priority: 'normal',
      createdAt: event.timestamp,
    });
  }

  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    await this.send({
      id: generateNotificationId(),
      type: 'order_status_update',
      channel: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      priority: event.newStatus === 'cancelled' ? 'high' : 'normal',
      createdAt: event.timestamp,
    });
  }

  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    await this.send({
      id: generateNotificationId(),
      type: 'welcome',
      channel: 'email',
      recipient: event.user.email,
      subject: 'Welcome to TaskFlow Pro',
      body: `Welcome, ${event.user.name}! Your account has been created.`,
      priority: 'normal',
      createdAt: event.timestamp,
    });
  }

  private async handleUserUpdated(event: UserUpdatedEvent): Promise<void> {
    await this.send({
      id: generateNotificationId(),
      type: 'account_updated',
      channel: 'email',
      recipient: event.user.email,
      subject: 'Account Updated',
      body: `Your account has been updated. Changed fields: ${event.changes.join(', ')}.`,
      priority: 'low',
      createdAt: event.timestamp,
    });
  }

  // --- Query methods ---

  /**
   * Get all notification records (payload + result).
   */
  getRecords(): NotificationRecord[] {
    return [...this.records];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getRecordsForRecipient(recipient: string): NotificationRecord[] {
    return this.records.filter((r) => r.payload.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.records.length;
  }

  /**
   * Clear all records (useful for testing).
   */
  clearRecords(): void {
    this.records = [];
  }
}

