import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('NotificationService', () => {
  let eventBus: EventBus;
  let service: NotificationService;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    eventBus = new EventBus();
    service = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter();
    service.registerAdapter(emailAdapter);
    resetNotificationIdCounter();
  });

  describe('order:created handler', () => {
    it('should send notification on order created', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const records = service.getRecords();
      expect(records).toHaveLength(1);
      expect(records[0]?.payload.recipient).toBe('alice@example.com');
      expect(records[0]?.payload.subject).toContain('Order Confirmation');
      expect(records[0]?.payload.body).toContain('Widget x2');
      expect(records[0]?.payload.body).toContain('$20.00');
      expect(records[0]?.result.success).toBe(true);
    });

    it('should include all items in notification body', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const records = service.getRecords();
      expect(records[0]?.payload.body).toContain('Widget x2');
      expect(records[0]?.payload.body).toContain('Gadget x1');
    });
  });

  describe('order:status-changed handler', () => {
    it('should send notification on status change via EventBus', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const records = service.getRecords();
      expect(records).toHaveLength(1);
      expect(records[0]?.payload.subject).toContain('Order Update');
      expect(records[0]?.payload.body).toContain('pending');
      expect(records[0]?.payload.body).toContain('confirmed');
      expect(records[0]?.result.success).toBe(true);
    });
  });

  describe('notification management', () => {
    it('should count notifications', async () => {
      expect(service.getNotificationCount()).toBe(0);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(service.getNotificationCount()).toBe(1);
    });

    it('should filter by recipient', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(service.getRecordsForRecipient('alice@example.com')).toHaveLength(1);
      expect(service.getRecordsForRecipient('bob@example.com')).toHaveLength(0);
    });

    it('should clear records', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      service.clearRecords();
      expect(service.getNotificationCount()).toBe(0);
    });

    it('should generate sequential notification IDs', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-2',
          userId: 'user-1',
          items: [],
          total: 30,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      const records = service.getRecords();
      expect(records[0]?.payload.id).toBe('notif-0001');
      expect(records[1]?.payload.id).toBe('notif-0002');
    });
  });

  describe('adapter routing', () => {
    it('should fail gracefully when no adapter is registered for channel', async () => {
      const noAdapterService = new NotificationService(new EventBus());
      const result = await noAdapterService.send({
        id: 'test-1',
        type: 'order_confirmation',
        channel: 'email',
        recipient: 'test@example.com',
        subject: 'Test',
        body: 'Test body',
        priority: 'normal',
        createdAt: new Date(),
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('No adapter registered');
    });

    it('should route to email adapter', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      const emails = emailAdapter.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.subject).toContain('Order Update');
    });
  });
});

